const API = process.env.REACT_APP_API_URL || "http://127.0.0.1:8000";


// =========================
// AUTH (FIXED FOR YOUR BACKEND)
// =========================

export const registerUser = async (data) => {
  const res = await fetch(`${API}/api/auth/api/auth/register`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};

export const loginUser = async (data) => {
  const res = await fetch(`${API}/api/auth/api/auth/login`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};


// =========================
// PATIENTS
// =========================

export const getPatients = async () => {
  const res = await fetch(`${API}/api/patients/`);
  return res.json();
};

export const addPatient = async (data) => {
  const res = await fetch(`${API}/api/patients/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};

export const searchPatientByPhone = async (phone) => {
  const res = await fetch(`${API}/api/patients/search/phone/${phone}`);
  return res.json();
};

export const searchPatientById = async (id) => {
  const res = await fetch(`${API}/api/patients/search/id/${id}`);
  return res.json();
};


// =========================
// APPOINTMENTS
// =========================

export const getAppointments = async () => {
  const res = await fetch(`${API}/api/appointments/`);
  return res.json();
};

export const addAppointment = async (data) => {
  const res = await fetch(`${API}/api/appointments/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};


// =========================
// PRESCRIPTIONS
// =========================

export const getPrescriptions = async (patientId) => {
  const res = await fetch(`${API}/api/prescriptions/${patientId}`);
  return res.json();
};

export const addPrescription = async (data) => {
  const res = await fetch(`${API}/api/prescriptions/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};
